// Extract message data from webhook
const body = $input.first().json.body;

return {
  json: {
    sessionId: body.sessionId,
    tenantId: body.tenantId,
    userMessage: body.payload?.content,
    messageType: body.payload?.type,
    user: body.user,
    context: body.context
  }
};

// Generate simple echo response
const userMessage = $input.first().json.userMessage;
const sessionId = $input.first().json.sessionId;

// Simple greeting detection
const greetings = ['hello', 'hi', 'hey', 'greetings'];
const isGreeting = greetings.some(g => userMessage.toLowerCase().includes(g));

let responseText;
if (isGreeting) {
  responseText = "Hello! Welcome to our chatbot. How can I help you today?";
} else if (userMessage.toLowerCase().includes('help')) {
  responseText = "I can help you with:\n• General questions\n• Product information\n• Support requests\nWhat do you need assistance with?";
} else if (userMessage.toLowerCase().includes('bye')) {
  responseText = "Goodbye! Have a great day!";
} else {
  responseText = `You said:

\n\nI'm a simple echo bot. Try saying 'hello', 'help', or 'bye'.`;
}

return {
  json: {
    action: 'message.send',
    sessionId: sessionId,
    payload: {
      type: 'text',
      content: responseText,
      quickReplies: ['Hello', 'Help', 'Bye']
    }
  }
};

// Handle non-text messages
const sessionId = $input.first().json.sessionId;
const messageType = $input.first().json.messageType;

return {
  json: {
    action: 'message.send',
    sessionId: sessionId,
    payload: {
      type: 'text',
      content: `I received a ${messageType} message, but I can only process text right now. Please type your message.`,
      quickReplies: ['Send text message']
    }
  }
};
